mapper.select:
SELECT mbu.id AS id, mbu.user_id as userId, mbu.reason AS reason ,IF(LENGTH(mu.phone) = 11,CONCAT(SUBSTRING(mu.phone, 1, 3), '****', SUBSTRING(mu.phone, 8, 4)), mu.phone) AS phone , mu.nickname AS nickname,mu.email AS email, mbu.create_time as createTime,mbu.operator_nickname AS operName FROM md_black_user mbu LEFT JOIN md_user mu ON mbu.user_id = mu.id WHERE mbu.app_id = #{blackUserListParam.appId}
AND mbu.create_time > #{blackUserListParam.beginTime}
AND #{blackUserListParam.endTime} > mbu.create_time
AND (mbu.reason like concat('%',#{blackUserListParam.reason},'%') OR mbu.reason like LOWER(concat('%',#{blackUserListParam.reason},'%')) OR mbu.reason like UPPER(concat('%',#{blackUserListParam.reason},'%')))
AND (mu.nickname like concat('%',#{blackUserListParam.keyword},'%') OR mu.nickname like LOWER(concat('%',#{blackUserListParam.keyword},'%')) OR mu.nickname like UPPER(concat('%',#{blackUserListParam.keyword},'%')) OR mu.phone like concat('%',#{blackUserListParam.keyword},'%') OR mu.email like concat('%',#{blackUserListParam.keyword},'%') OR mu.email like LOWER(concat('%',#{blackUserListParam.keyword},'%')) OR mu.email like UPPER(concat('%',#{blackUserListParam.keyword},'%')))
ORDER BY mbu.create_time DESC
